// Parse YouTube PubSubHubbub XML notification
const body = $input.first().json.body || $input.first().json;
const rawXml = typeof body === 'string' ? body : JSON.stringify(body);

// Extract video ID from XML
const videoIdMatch = rawXml.match(/<yt:videoId>([^<]+)<\/yt:videoId>/);
const titleMatch = rawXml.match(/<title>([^<]+)<\/title>/);
const publishedMatch = rawXml.match(/<published>([^<]+)<\/published>/);
const channelIdMatch = rawXml.match(/<yt:channelId>([^<]+)<\/yt:channelId>/);

const videoId = videoIdMatch ? videoIdMatch[1].trim() : null;
const title = titleMatch ? titleMatch[1].replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').trim() : 'New Video';
const published = publishedMatch ? publishedMatch[1].trim() : new Date().toISOString();
const channelId = channelIdMatch ? channelIdMatch[1].trim() : $env['YOUTUBE_CHANNEL_ID'];

if (!videoId) {
  throw new Error('Could not parse video ID from YouTube notification');
}

const videoUrl = `https://youtu.be/${videoId}`;
const thumbnailUrl = `https://img.youtube.com/vi/${videoId}/maxresdefault.jpg`;

return [{
  json: {
    videoId,
    videoUrl,
    thumbnailUrl,
    title,
    published,
    channelId,
    channelUrl: `https://www.youtube.com/channel/${channelId}`
  }
}];

const webhook = $('Code - Parse YouTube XML').first().json;
const ytData = $input.first().json;
const video = ytData.items?.[0]?.snippet || {};
const stats = ytData.items?.[0]?.statistics || {};

const description = (video.description || '').substring(0, 300);
const tags = (video.tags || []).slice(0, 10).join(', ');

// Generate platform-specific content
const tweetText = `🎬 New video just dropped!\n\n"${webhook.title}"\n\nWatch now 👇\n${webhook.videoUrl}\n\n#YouTube #NewVideo`;
const slackMessage = `🎬 *New YouTube Video Published!*\n\n*${webhook.title}*\n${description ? description + '...' : ''}\n\n👉 ${webhook.videoUrl}`;
const instagramCaption = `🎬 New video is LIVE!\n\n${webhook.title}\n\n${description.substring(0, 150)}...\n\n🔗 Link in bio!\n\n${tags.split(', ').map(t => '#' + t.replace(/\s+/g, '')).join(' ')}`;

return [{
  json: {
    ...webhook,
    channelTitle: video.channelTitle || '',
    description,
    tags,
    categoryId: video.categoryId,
    tweetText: tweetText.substring(0, 280),
    slackMessage,
    instagramCaption: instagramCaption.substring(0, 2200),
    thumbnailHq: video.thumbnails?.maxres?.url || video.thumbnails?.high?.url || webhook.thumbnailUrl
  }
}];
